import request from '@/utils/request'

export function updateVoteConfig(id, data) {
  return request({
    url: `/voteBasicConfiguration/updateVote?id=${id}`,
    method: 'post',
    data: data,
  })
}

export function addVoteConfig(data) {
  return request({
    url: `/voteBasicConfiguration/add`,
    method: 'post',
    data: data,
  })
}

export function delVoteConfig(id) {
  return request({
    url: `/voteBasicConfiguration/delete?id=${id}`,
    method: 'post',
  })
}

export function voteBasicConfigurationList() {
  return request({
    url: '/voteBasicConfiguration/selectAll?page=1&pageSize=100',
    method: 'get',
  })
}

export function voteBasicConfigurationDetail(params) {
  return request({
    url: '/voteBasicConfiguration/selectById',
    method: 'get',
    params: params,
  })
}
